import { useRoutes, Navigate, useLocation } from "react-router-dom";
import { useState } from "react";
import classes from "./app.module.css";
import Home from "../components/pages/Home";
import Login from "../components/pages/Login";
import CalorieCalc from "../components/pages/CalorieCalc";
import Profile from "../components/pages/Profile";
import NavBar from "../components/navBar/NavBar";
import NotFound from "../components/pages/NotFound";

// Define pages configuration
const pages = [
  { name: "Login", path: "/" },
  { name: "Home", path: "/home" },
  { name: "CalorieCalculator", path: "/CalorieCalc" },
  { name: "Profile", path: "/profile" },
];

// Authentication guard component
const RequireAuth = ({ children }) => {
  const location = useLocation();
  const isLoggedIn = false; // This would normally come from auth state

  if (!isLoggedIn) {
    return <Navigate to="/" state={{ from: location }} replace />;
  }

  return children;
};

export default function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);

  // Authentication handlers
  const handleLogin = (user) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setCurrentUser(null);
  };

  const routes = useRoutes([
    {
      path: "/",
      element: <Login onLoginSuccess={handleLogin} />,
    },
    {
      path: "/home",
      element: (
        <>
          <RequireAuth>
            <>
              <NavBar
                pages={pages}
                isLoggedIn={isLoggedIn}
                onLogout={handleLogout}
                currentUser={currentUser}
              />
              <Home />
            </>
          </RequireAuth>
        </>
      ),
    },
    {
      path: "/CalorieCalc",
      element: (
        <>
          <RequireAuth>
            <>
              <NavBar
                pages={pages}
                isLoggedIn={isLoggedIn}
                onLogout={handleLogout}
                currentUser={currentUser}
              />
              <CalorieCalc />
            </>
          </RequireAuth>
        </>
      ),
    },
    {
      path: "/profile",
      element: (
        <>
          <RequireAuth>
            <>
              <NavBar
                pages={pages}
                isLoggedIn={isLoggedIn}
                onLogout={handleLogout}
                currentUser={currentUser}
              />
              <Profile />
            </>
          </RequireAuth>
        </>
      ),
    },
    {
      path: "*",
      element: <NotFound />,
    },
  ]);

  return <section className={classes.app}>{routes}</section>;
}
